import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

function Login() {
  const [isRegister, setIsRegister] = useState(false);
  const [form, setForm] = useState({
    name: "",
    tenDangNhap: "",
    email: "",
    password: "",
    diaChi: "",
    soDienThoai: "",
  });
  const [error, setError] = useState("");
  const { login, register } = useAuth();
  const navigate = useNavigate();

  const set = (key) => (e) => setForm((f) => ({ ...f, [key]: e.target.value }));

  const handleSubmit = () => {
    setError("");
    if (!form.email.trim() || !form.password.trim()) {
      setError("Vui lòng điền đầy đủ thông tin!");
      return;
    }
    if (isRegister) {
      if (!form.name.trim()) {
        setError("Vui lòng nhập họ tên!");
        return;
      }
      if (!form.soDienThoai.trim()) {
        setError("Vui lòng nhập số điện thoại!");
        return;
      }
      const ok = register(form);
      if (!ok) {
        setError("Email đã được sử dụng!");
        return;
      }
    } else {
      const ok = login(form.email, form.password);
      if (!ok) {
        setError("Email hoặc mật khẩu không đúng!");
        return;
      }
    }
    navigate("/");
  };

  return (
    <div style={styles.page}>
      <div style={styles.card}>
        {/* Logo */}
        <div style={styles.logo}>
          <span style={{ fontSize: "48px" }}>🛒</span>
          <h2 style={styles.logoText}>FoodMart</h2>
          <p style={styles.logoSub}>Siêu Thị Thực Phẩm Online</p>
        </div>

        {/* Tabs */}
        <div style={styles.tabs}>
          <button
            style={{ ...styles.tab, ...(!isRegister ? styles.tabActive : {}) }}
            onClick={() => {
              setIsRegister(false);
              setError("");
            }}
          >
            Đăng Nhập
          </button>
          <button
            style={{ ...styles.tab, ...(isRegister ? styles.tabActive : {}) }}
            onClick={() => {
              setIsRegister(true);
              setError("");
            }}
          >
            Đăng Ký
          </button>
        </div>

        {/* Form */}
        <div style={styles.form}>
          {error && <div style={styles.error}>⚠️ {error}</div>}

          {isRegister && (
            <>
              <div style={styles.row}>
                <div style={styles.field}>
                  <label style={styles.label}>👤 Họ và tên *</label>
                  <input
                    style={styles.input}
                    type="text"
                    placeholder="Nguyễn Văn A"
                    value={form.name}
                    onChange={set("name")}
                  />
                </div>
                <div style={styles.field}>
                  <label style={styles.label}>🏷️ Tên đăng nhập</label>
                  <input
                    style={styles.input}
                    type="text"
                    placeholder="nguyenvana"
                    value={form.tenDangNhap}
                    onChange={set("tenDangNhap")}
                  />
                </div>
              </div>
              <div style={styles.row}>
                <div style={styles.field}>
                  <label style={styles.label}>📞 Số điện thoại *</label>
                  <input
                    style={styles.input}
                    type="tel"
                    placeholder="0901234567"
                    value={form.soDienThoai}
                    onChange={set("soDienThoai")}
                  />
                </div>
                <div style={styles.field}>
                  <label style={styles.label}>📍 Địa chỉ</label>
                  <input
                    style={styles.input}
                    type="text"
                    placeholder="Hà Nội"
                    value={form.diaChi}
                    onChange={set("diaChi")}
                  />
                </div>
              </div>
            </>
          )}

          <div style={styles.field}>
            <label style={styles.label}>📧 Email *</label>
            <input
              style={styles.input}
              type="email"
              placeholder="example@email.com"
              value={form.email}
              onChange={set("email")}
            />
          </div>

          <div style={styles.field}>
            <label style={styles.label}>🔒 Mật khẩu *</label>
            <input
              style={styles.input}
              type="password"
              placeholder="Nhập mật khẩu"
              value={form.password}
              onChange={set("password")}
              onKeyDown={(e) => e.key === "Enter" && handleSubmit()}
            />
          </div>

          <button style={styles.submitBtn} onClick={handleSubmit}>
            {isRegister ? "✅ Đăng Ký" : "🔑 Đăng Nhập"}
          </button>

          <p style={styles.switchText}>
            {isRegister ? "Đã có tài khoản? " : "Chưa có tài khoản? "}
            <span
              style={styles.switchLink}
              onClick={() => {
                setIsRegister(!isRegister);
                setError("");
              }}
            >
              {isRegister ? "Đăng nhập" : "Đăng ký ngay"}
            </span>
          </p>

          
        </div>
      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    backgroundColor: "#f0fff4",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontFamily: "sans-serif",
    padding: "20px",
  },
  card: {
    backgroundColor: "white",
    borderRadius: "20px",
    padding: "40px",
    width: "100%",
    maxWidth: "480px",
    boxShadow: "0 8px 32px rgba(0,0,0,0.12)",
  },
  logo: { textAlign: "center", marginBottom: "24px" },
  logoText: {
    fontSize: "28px",
    fontWeight: "800",
    color: "#2d3748",
    margin: "8px 0 4px",
  },
  logoSub: { fontSize: "13px", color: "#718096", margin: 0 },
  tabs: {
    display: "flex",
    backgroundColor: "#f7fafc",
    borderRadius: "10px",
    padding: "4px",
    marginBottom: "24px",
  },
  tab: {
    flex: 1,
    padding: "10px",
    border: "none",
    borderRadius: "8px",
    fontSize: "14px",
    fontWeight: "600",
    cursor: "pointer",
    backgroundColor: "transparent",
    color: "#718096",
  },
  tabActive: {
    backgroundColor: "#38a169",
    color: "white",
    boxShadow: "0 2px 6px rgba(56,161,105,0.4)",
  },
  form: { display: "flex", flexDirection: "column", gap: "4px" },
  error: {
    backgroundColor: "#fff5f5",
    color: "#e53e3e",
    border: "1px solid #fed7d7",
    borderRadius: "8px",
    padding: "10px 14px",
    fontSize: "13px",
    fontWeight: "600",
    marginBottom: "8px",
  },
  row: { display: "flex", gap: "12px" },
  field: { flex: 1, marginBottom: "14px" },
  label: {
    display: "block",
    fontSize: "13px",
    fontWeight: "600",
    color: "#4a5568",
    marginBottom: "6px",
  },
  input: {
    width: "100%",
    padding: "12px 14px",
    border: "2px solid #e2e8f0",
    borderRadius: "8px",
    fontSize: "14px",
    outline: "none",
    boxSizing: "border-box",
  },
  submitBtn: {
    width: "100%",
    backgroundColor: "#38a169",
    color: "white",
    border: "none",
    padding: "14px",
    borderRadius: "10px",
    fontSize: "16px",
    fontWeight: "700",
    cursor: "pointer",
    marginTop: "8px",
